import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionExample {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a directory name: ");
            String directoryName = reader.readLine();

            // Create a list to store the command and arguments
            ProcessBuilder processBuilder = new ProcessBuilder();

            // Set the command and arguments securely
            processBuilder.command("ls", directoryName);

            // Start the process and read its output
            Process process = processBuilder.start();

            BufferedReader inputStream = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String output = null;

            while ((output = inputStream.readLine()) != null) {
                System.out.println(output);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

